<template>
  <div>
    <div id="main"></div>
    
    事件包括：
    <p>点击事件</p>
    <p>左滑事件</p>
    <p>右滑事件</p>
    <p>下滑事件</p>
    <p>上滑事件</p>
    <p>长按事件 timegap > 1000</p>
    <button id="test">解除左滑绑定</button>
  </div>
</template>

<script>
export default {
  name: "touchmove", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      domContent: null,
      btnTest: null,
    };
  },
  computed: {},
  created() {},
  mounted() {
    this.domContent = document.querySelector("#main");
    //接触绑定按钮
    this.btnTest = document.querySelector("#test");
    //绑定点击事件
    EventUtil.bindEvent(this.domContent, "click", this.handleClick);
    //绑定两次左滑事件
    EventUtil.bindEvent(this.domContent, "swipeleft", this.handleLeft);
    EventUtil.bindEvent(this.domContent, "swipeleft", this.handleLeft);
    //绑定右滑事件
    EventUtil.bindEvent(this.domContent, "swiperight", this.handleRight);
    //上滑事件
    EventUtil.bindEvent(this.domContent, "slideup", this.handleUp);
    //下滑事件
    EventUtil.bindEvent(this.domContent, "slidedown", this.handleDown);
    //长按点击事件
    EventUtil.bindEvent(this.domContent, "longpress", this.handleLong);
    EventUtil.bindEvent(this.btnTest, "click", this.removeLeft);
    this.$once("hook:destroyed",()=>{
      EventUtil.removeEvent(this.domContent, "click", this.handleClick)
    //绑定两次左滑事件
    EventUtil.removeEvent(this.domContent, "swipeleft", this.handleLeft);
    EventUtil.removeEvent(this.domContent, "swipeleft", this.handleLeft);
    //绑定右滑事件
    EventUtil.removeEvent(this.domContent, "swiperight", this.handleRight);
    //上滑事件
    EventUtil.removeEvent(this.domContent, "slideup", this.handleUp);
    //下滑事件
    EventUtil.removeEvent(this.domContent, "slidedown", this.handleDown);
    //长按点击事件
    EventUtil.removeEvent(this.domContent, "longpress", this.handleLong);
    EventUtil.removeEvent(this.btnTest, "click", this.removeLeft);
    })
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //获取dom

    //定义各类事件，为了可以解除事件绑定，事件回调不使用匿名函数
    handleClick() {
      alert("点击事件");
    },
    handleLeft() {
      alert("左滑事件");
    },
    handleRight() {
      alert("右滑事件");
    },
    handleUp() {
      alert("下滑事件");
    },
    handleDown() {
      alert("上滑事件");
    },
    handleLong() {
      alert("长按事件");
    },

    removeLeft() {
      //接触左滑事件绑定
      EventUtil.removeEvent(this.domContent, "swipeleft", handleLeft);
    },
    //绑定点击事件
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
#main {
  width: 100%;
  height: 300px;
  background: #eee685;
  color: white;
  font-size: 20px;
  text-align: center;
}
</style>